import{_ as e,o as d,c as a,a4 as r}from"./chunks/framework.DiadTcoQ.js";const m=JSON.parse('{"title":"Les adjectifs","description":"","frontmatter":{},"headers":[],"relativePath":"module-3/adjectives.md","filePath":"module-3/adjectives.md"}'),n={name:"module-3/adjectives.md"};function o(i,t,l,s,c,u){return d(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="les-adjectifs" tabindex="-1">Les adjectifs <a class="header-anchor" href="#les-adjectifs" aria-label="Permalink to “Les adjectifs”">​</a></h1><h2 id="l-accord" tabindex="-1">L&#39;accord <a class="header-anchor" href="#l-accord" aria-label="Permalink to “L&#39;accord”">​</a></h2><p>En espagnol, les adjectifs s&#39;accordent en genre et en nombre avec le nom qu&#39;ils qualifient.</p><table tabindex="0"><thead><tr><th></th><th>Masculin</th><th>Féminin</th></tr></thead><tbody><tr><td>Singulier</td><td>un chico alto</td><td>una chica alta</td></tr><tr><td>Pluriel</td><td>unos chicos altos</td><td>unas chicas altas</td></tr></tbody></table><p><strong>Adjectifs en -e ou consonne</strong> — invariables en genre, seulement le nombre change :</p><table tabindex="0"><thead><tr><th></th><th>Singulier</th><th>Pluriel</th></tr></thead><tbody><tr><td></td><td>un hombre inteligente</td><td>unos hombres inteligentes</td></tr><tr><td></td><td>una mujer inteligente</td><td>unas mujeres inteligentes</td></tr></tbody></table><h2 id="la-place-de-l-adjectif" tabindex="-1">La place de l&#39;adjectif <a class="header-anchor" href="#la-place-de-l-adjectif" aria-label="Permalink to “La place de l&#39;adjectif”">​</a></h2><p><strong>Après le nom</strong> — règle générale :</p><blockquote><p><em>una casa grande</em> — une grande maison <em>un coche rojo</em> — une voiture rouge</p></blockquote><p><strong>Avant le nom</strong> — pour exprimer une qualité inhérente ou stylistique :</p><blockquote><p><em>la blanca nieve</em> — la blanche neige <em>un buen amigo</em> — un bon ami</p></blockquote><h3 id="adjectifs-qui-changent-de-sens-selon-la-place" tabindex="-1">Adjectifs qui changent de sens selon la place <a class="header-anchor" href="#adjectifs-qui-changent-de-sens-selon-la-place" aria-label="Permalink to “Adjectifs qui changent de sens selon la place”">​</a></h3><table tabindex="0"><thead><tr><th>Adjectif</th><th>Avant le nom</th><th>Après le nom</th></tr></thead><tbody><tr><td>grande → gran</td><td>un gran hombre — un grand homme (remarquable)</td><td>un hombre grande — un homme grand (physiquement)</td></tr><tr><td>mismo</td><td>el mismo día — le même jour</td><td>el día mismo — le jour en question</td></tr><tr><td>viejo</td><td>un viejo amigo — un vieil ami (de longue date)</td><td>un amigo viejo — un ami âgé</td></tr><tr><td>nuevo</td><td>un nuevo coche — une nouvelle voiture (différente)</td><td>un coche nuevo — une voiture neuve</td></tr><tr><td>pobre</td><td>un pobre hombre — un pauvre homme (malheureux)</td><td>un hombre pobre — un homme pauvre (sans argent)</td></tr></tbody></table><h2 id="formes-abregees" tabindex="-1">Formes abrégées <a class="header-anchor" href="#formes-abregees" aria-label="Permalink to “Formes abrégées”">​</a></h2><p>Certains adjectifs perdent leur dernière syllabe devant un nom masculin singulier :</p><table tabindex="0"><thead><tr><th>Forme complète</th><th>Forme abrégée</th><th>Exemple</th></tr></thead><tbody><tr><td>bueno</td><td>buen</td><td>un buen día</td></tr><tr><td>malo</td><td>mal</td><td>un mal momento</td></tr><tr><td>grande</td><td>gran</td><td>un gran problema</td></tr><tr><td>primero</td><td>primer</td><td>el primer piso</td></tr><tr><td>tercero</td><td>tercer</td><td>el tercer módulo</td></tr></tbody></table><h2 id="adjectifs-courants" tabindex="-1">Adjectifs courants <a class="header-anchor" href="#adjectifs-courants" aria-label="Permalink to “Adjectifs courants”">​</a></h2><table tabindex="0"><thead><tr><th>Espagnol</th><th>Français</th><th>Espagnol</th><th>Français</th></tr></thead><tbody><tr><td>grande</td><td>grand(e)</td><td>pequeño/a</td><td>petit(e)</td></tr><tr><td>alto/a</td><td>grand(e) / haut(e)</td><td>bajo/a</td><td>petit(e) / bas(se)</td></tr><tr><td>bueno/a</td><td>bon(ne)</td><td>malo/a</td><td>mauvais(e)</td></tr><tr><td>bonito/a</td><td>joli(e)</td><td>feo/a</td><td>laid(e)</td></tr><tr><td>nuevo/a</td><td>nouveau/nouvelle</td><td>viejo/a</td><td>vieux/vieille</td></tr><tr><td>rápido/a</td><td>rapide</td><td>lento/a</td><td>lent(e)</td></tr><tr><td>fácil</td><td>facile</td><td>difícil</td><td>difficile</td></tr><tr><td>barato/a</td><td>bon marché</td><td>caro/a</td><td>cher/chère</td></tr><tr><td>caliente</td><td>chaud(e)</td><td>frío/a</td><td>froid(e)</td></tr></tbody></table>',18)])])}const b=e(n,[["render",o]]);export{m as __pageData,b as default};
